import { isUndefined } from 'lodash-es';
import { type CSSProperties, useEffect, useState } from 'react';

import { CONTAINER_CSS_PROPS, ESTIMATED_ITEM_SIZE } from '../../constants.js';
import { useChartTooltipMetadata } from '../../context/ChartTooltipMetadataContext.js';
import { HEADER_SECTION_NAME } from '../../section-components/TooltipHeader/TooltipHeader.js';

/**
 * Hook responsible to calculate the correct values for height and max height
 * to use for the body (considering the size of the optional header).
 * @param totalSize -
 * @param bodyItemsCount -
 */
export const useBodyHeightStyle = (
  totalSize?: number,
  bodyItemsCount?: number,
): CSSProperties => {
  const [headerElementRect, setHeaderElementRect] = useState<DOMRect>();
  const { tooltipRef } = useChartTooltipMetadata();

  useEffect(() => {
    if (!tooltipRef?.current) {
      return;
    }
    const tooltipContent = tooltipRef.current?.children?.[0]?.children;
    const hasHeader =
      tooltipContent[0]?.className.includes(HEADER_SECTION_NAME);

    if (hasHeader) {
      setHeaderElementRect(tooltipContent[0].getBoundingClientRect());
    }
  }, [tooltipRef]);

  const isVirtualized = !isUndefined(totalSize) && !isUndefined(bodyItemsCount);

  return {
    height: isVirtualized
      ? totalSize || `${ESTIMATED_ITEM_SIZE * bodyItemsCount}px`
      : '100%',
    maxHeight: `calc(${CONTAINER_CSS_PROPS.maxHeight} - ${
      headerElementRect?.height ?? 0
    }px)`,
  };
};
